p.m:
\displaystyle{\begin{aligned}
   \frac{5}{8} + \frac{23}{24}
        \amp = \frac{15}{24} + \frac{23}{24} \\
        \amp = \frac{15 + 23}{24} \\
        \amp = \frac{38}{24} \amp  \hbox{We can reduce this by dividing 2 into both the numerator and the denominator.}\\
        \amp = \frac{19}{12}
\end{aligned}
    }
